import{_ as i,o as l,c as a,e}from"./app-4cb4de65.js";const r={},h=e('<h1 id="精力管理" tabindex="-1"><a class="header-anchor" href="#精力管理" aria-hidden="true">#</a> 精力管理</h1><h2 id="什么是精力" tabindex="-1"><a class="header-anchor" href="#什么是精力" aria-hidden="true">#</a> 什么是精力</h2><p>精力就是做事情的能力。包括体能、情感、思维、意志四个方面。</p><h3 id="管理精力是高效表现的关键" tabindex="-1"><a class="header-anchor" href="#管理精力是高效表现的关键" aria-hidden="true">#</a> 管理精力是高效表现的关键</h3><h4 id="核心思想" tabindex="-1"><a class="header-anchor" href="#核心思想" aria-hidden="true">#</a> 核心思想</h4><ul><li>管理精力,而非时间</li><li>全情投入 <ul><li>高效</li><li>健康</li><li>快乐</li></ul></li><li>像专业运动员那样管理精力</li></ul><h4 id="全情投入" tabindex="-1"><a class="header-anchor" href="#全情投入" aria-hidden="true">#</a> 全情投入</h4><ul><li>四种精力来源 <ul><li>体能</li><li>情感</li><li>思维</li><li>意志</li></ul></li><li>钟摆式运动 <ul><li>精力储备消耗</li><li>周期性补充才能平衡消耗</li><li>突破舒适区</li></ul></li><li>积极的仪式习惯</li></ul><h4 id="精力训练的步骤" tabindex="-1"><a class="header-anchor" href="#精力训练的步骤" aria-hidden="true">#</a> 精力训练的步骤</h4><ul><li>明确目标 <ul><li>按价值观来支配精力</li></ul></li><li>正视现实 <ul><li>你是谁?</li><li>评估</li></ul></li><li>付诸行动</li></ul><p>我们生活在数字时代，节奏如电光火石般迅猛，似乎永不间断，时间被打碎成了比特和字节。我们对广度的热爱超过了对深度的关注，注重反应速度却不愿深入思考。我们流连于事物的表象，满足浅尝辄止的片刻欢愉，却几乎从不久留。我们在人生的道路上争先恐后，却吝于用片刻思考目标或方向。我们事务缠身，却又总是筋疲力尽。</p>',11),d=[h];function t(n,c){return l(),a("div",null,d)}const s=i(r,[["render",t],["__file","精力管理.html.vue"]]);export{s as default};
